const ALLOW = new Set(['KubePodOOMKilled', 'KubePodCrashLoopBackOff']);
const body = $input.first().json.body ?? $input.first().json;
if (body.status === 'resolved') {
  return [{ json: { skip: true, reason: 'resolved', status: 'resolved' } }];
}
const alerts = body.alerts || [];
const first = alerts[0] || {};
const labels = { ...(body.commonLabels || {}), ...(first.labels || {}) };
const annotations = { ...(body.commonAnnotations || {}), ...(first.annotations || {}) };
const alertname = labels.alertname || body.groupLabels?.alertname || '';
if (!ALLOW.has(alertname)) {
  return [{ json: { skip: true, reason: 'not_allowlisted', alertname } }];
}
const namespace = labels.namespace || '';
const pod = labels.pod || labels.instance || '';
const container = labels.container || '';
const error = alertname === 'KubePodOOMKilled' ? 'OOMKilled' : 'CrashLoopBackOff';
return [{
  json: {
    skip: false,
    status: 'firing',
    alertname,
    namespace,
    pod,
    container,
    error,
    severity: labels.severity || 'critical',
    summary: annotations.summary || '',
    description: annotations.description || '',
    runbookUrl: annotations.runbook_url || '',
    fingerprint: first.fingerprint || '',
    raw: body,
  },
}];

const alert = $('Parse VM Payload').first().json;
const base = ($env.LLM_BASE_URL || 'https://api.openai.com/v1').replace(/\/$/, '');
const system = [
  'Du bist ein Kubernetes GitOps Engineer. Antworte NUR mit gültigem JSON (kein Markdown, kein Code-Fence):',
  '{',
  '  "action": "patch|noop|needs_human",',
  '  "risk": "low|medium|high",',
  '  "summary_de": "string",',
  '  "target_file": "relativer Pfad unter gitops-homelab/",',
  '  "patch_yaml": "multi-line YAML",',
  '  "pr_title": "string",',
  '  "pr_body": "string (Markdown)"',
  '}',
  'Regeln: nur gitops-homelab/ im Repo homelab-gitops; neue Dateien unter apps/base/<app>/patches/ bevorzugen; kein kubectl apply.',
].join('\n');
const user = [
  'Alert: ' + alert.alertname,
  'Namespace: ' + alert.namespace,
  'Pod: ' + alert.pod,
  'Container: ' + alert.container,
  'Error: ' + alert.error,
  'Summary: ' + alert.summary,
  'Description: ' + alert.description,
].join('\n');
const res = await this.helpers.httpRequest({
  method: 'POST',
  url: base + '/chat/completions',
  headers: {
    Authorization: 'Bearer ' + $env.LLM_API_KEY,
    'Content-Type': 'application/json',
  },
  body: {
    model: 'gpt-4o-mini',
    temperature: 0.1,
    max_tokens: 2500,
    messages: [
      { role: 'system', content: system },
      { role: 'user', content: user },
    ],
  },
  json: true,
});
const content = res?.choices?.[0]?.message?.content ?? '';
return [{ json: { message: { content } } }];

const alert = $('Parse VM Payload').first().json;
const api = ($env.GITHUB_API_URL || 'https://api.github.com').replace(/\/$/, '');
let plan = {};
try {
  const raw = $input.first().json.message?.content ?? $input.first().json.text ?? '';
  const m = String(raw).match(/\{[\s\S]*\}/);
  plan = m ? JSON.parse(m[0]) : { action: 'needs_human', summary_de: 'LLM nicht parsebar' };
} catch (e) {
  plan = { action: 'needs_human', summary_de: 'LLM parse error: ' + e.message };
}
if (plan.action !== 'patch' || !plan.patch_yaml || !plan.target_file) {
  return [{ json: { ...alert, plan, proceed: false, api } }];
}
const slug = `${alert.namespace}-${alert.pod}`.replace(/[^a-zA-Z0-9-]/g, '-').slice(0, 40);
const branch = `auto/remediate-${slug}-${Date.now().toString(36)}`;
const owner = $env.GITHUB_REPO_OWNER || 'kreativmonkey';
const repo = $env.GITHUB_REPO_NAME || 'homelab-gitops';
const base = $env.GITHUB_DEFAULT_BRANCH || 'main';
const manifestsPath = $env.GITOPS_MANIFESTS_PATH || 'gitops-homelab';
const filePath = plan.target_file.startsWith(manifestsPath)
  ? plan.target_file
  : `${manifestsPath}/${plan.target_file.replace(/^\/+/, '')}`;
return [{
  json: {
    ...alert,
    plan,
    proceed: true,
    api,
    branch,
    owner,
    repo,
    base,
    filePath,
    contentB64: Buffer.from(plan.patch_yaml, 'utf8').toString('base64'),
    commitMessage: `fix(auto): ${alert.alertname} ${alert.namespace}/${alert.pod}`,
    repoApi: `${api}/repos/${owner}/${repo}`,
    githubAuth: `Bearer ${$env.GITHUB_TOKEN}`,
  },
}];

